// Express.js 4.x Implementation with DPoP
// File: middleware/dpopTokenValidation.js
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const { createRemoteJWKSet, jwtVerify } = require('jose');

/**
 * DPoP Token Binding Middleware for Express.js 4.x
 * Implements RFC 9449 - OAuth 2.0 Demonstrating Proof-of-Possession
 */
const dpopTokenValidation = async (req, res, next) => {
    try {
        // 1. Extract access token from Authorization header
        const authHeader = req.headers.authorization;
        if (!authHeader || !authHeader.startsWith('Bearer ')) {
            return res.status(401).json({ error: 'Missing or invalid Authorization header' });
        }
        const accessToken = authHeader.substring(7);

        // 2. Extract DPoP proof from DPoP header
        const dpopProof = req.headers['dpop'];
        if (!dpopProof) {
            return res.status(401).json({ error: 'DPoP proof required' });
        }

        // 3. Decode DPoP proof (JWT) without verification first to get JWK
        const dpopDecoded = jwt.decode(dpopProof, { complete: true });
        if (!dpopDecoded || !dpopDecoded.header.jwk) {
            return res.status(401).json({ error: 'Invalid DPoP proof format' });
        }

        // 4. Verify DPoP proof JWT signature using public key from header
        const publicKey = await crypto.subtle.importKey(
            'jwk',
            dpopDecoded.header.jwk,
            { name: 'RSASSA-PKCS1-v1_5', hash: 'SHA-256' },
            false,
            ['verify']
        );

        const dpopPayload = jwt.verify(dpopProof, publicKey, {
            algorithms: ['RS256', 'ES256']
        });

        // 5. Validate DPoP proof claims
        const validations = [
            // HTTP method must match
            dpopPayload.htm === req.method,
            // HTTP URI must match (without query params)
            dpopPayload.htu === `${req.protocol}://${req.get('host')}${req.path}`,
            // Access token hash must match
            dpopPayload.ath === crypto.createHash('sha256').update(accessToken).digest('base64url'),
            // Timestamp must be recent (within 60 seconds)
            Math.abs(Date.now() / 1000 - dpopPayload.iat) < 60,
            // JTI must be unique (check Redis/database)
            await isJtiUnique(dpopPayload.jti)
        ];

        if (!validations.every(v => v === true)) {
            return res.status(401).json({ error: 'DPoP proof validation failed' });
        }

        // 6. Verify access token (with OAuth server's public key)
        const JWKS = createRemoteJWKSet(new URL('https://your-auth-server.com/.well-known/jwks.json'));
        const { payload: tokenPayload } = await jwtVerify(accessToken, JWKS, {
            issuer: 'https://your-auth-server.com',
            audience: 'your-api-identifier'
        });

        // 7. Verify token is bound to DPoP key (cnf claim)
        const tokenThumbprint = tokenPayload.cnf?.jkt;
        const dpopThumbprint = crypto.createHash('sha256')
            .update(JSON.stringify(dpopDecoded.header.jwk))
            .digest('base64url');

        if (tokenThumbprint !== dpopThumbprint) {
            return res.status(401).json({ error: 'Token not bound to DPoP key' });
        }

        // 8. Store user info and proceed
        req.user = tokenPayload;
        req.dpop = dpopPayload;
        next();

    } catch (error) {
        console.error('DPoP validation error:', error);
        return res.status(401).json({ error: 'Token validation failed' });
    }
};

