import org.springframework.data.redis.core.RedisTemplate;
import java.time.Duration;

@Service
public class RefreshTokenReuseDetectionService {

    private final OAuth2AuthorizationService authorizationService;
    private final RedisTemplate<String, String> redisTemplate;

    public RefreshTokenReuseDetectionService(
        OAuth2AuthorizationService authorizationService,
        RedisTemplate<String, String> redisTemplate
    ) {
        this.authorizationService = authorizationService;
        this.redisTemplate = redisTemplate;
    }

    public boolean detectAndHandleTokenReuse(String refreshToken) {
        String cacheKey = "refresh_token:" + refreshToken;

        // Check if token was already used
        Boolean tokenWasUsed = redisTemplate.hasKey(cacheKey);

        if (Boolean.TRUE.equals(tokenWasUsed)) {
            // TOKEN REUSE DETECTED - Possible theft!
            handleTokenTheft(refreshToken);
            return true;
        }

        // Mark token as used (expires after 7 days)
        redisTemplate.opsForValue().set(cacheKey, "used", Duration.ofDays(7));
        return false;
    }

    private void handleTokenTheft(String refreshToken) {
        // 1. Revoke all tokens for this authorization
        OAuth2Authorization authorization = authorizationService
            .findByToken(refreshToken, OAuth2TokenType.REFRESH_TOKEN);

        if (authorization != null) {
            // Revoke the authorization (invalidates all associated tokens)
            authorizationService.remove(authorization);

            // 2. Log security incident
            logSecurityIncident(authorization.getPrincipalName(), 
                "Refresh token reuse detected - possible token theft");

            // 3. Trigger alert to security team
            triggerSecurityAlert(authorization.getPrincipalName());

            // 4. Optionally: Force user to re-authenticate
            forceReAuthentication(authorization.getPrincipalName());
        }
    }

