const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const redis = require('./redisClient');
const { promisify } = require('util');

class TokenService {
    constructor() {
        this.ACCESS_TOKEN_EXPIRY = '10m'; // 10 minutes
        this.REFRESH_TOKEN_EXPIRY = '7d'; // 7 days
        this.JWT_SECRET = process.env.JWT_SECRET; // Load from secure vault
    }

    /**
     * Generate access token and refresh token pair
     */
    async generateTokenPair(userId, userRoles, clientId) {
        const accessToken = jwt.sign(
            {
                sub: userId,
                roles: userRoles,
                type: 'access',
                client_id: clientId
            },
            this.JWT_SECRET,
            {
                expiresIn: this.ACCESS_TOKEN_EXPIRY,
                issuer: 'https://your-auth-server.com',
                audience: 'your-api'
            }
        );

        // Generate cryptographically secure refresh token
        const refreshToken = crypto.randomBytes(40).toString('hex');

        // Store refresh token metadata in Redis
        const refreshTokenData = {
            userId,
            clientId,
            createdAt: Date.now(),
            used: false
        };

        await redis.setex(
            `refresh_token:${refreshToken}`,
            7 * 24 * 60 * 60, // 7 days in seconds
            JSON.stringify(refreshTokenData)
        );

        return { accessToken, refreshToken };
    }

    /**
     * Refresh access token using refresh token (with rotation)
     */
    async refreshAccessToken(refreshToken) {
        const tokenKey = `refresh_token:${refreshToken}`;

        // 1. Retrieve refresh token data
        const tokenDataStr = await redis.get(tokenKey);
        if (!tokenDataStr) {
            throw new Error('Invalid or expired refresh token');
        }

        const tokenData = JSON.parse(tokenDataStr);

        // 2. Check if token was already used (reuse detection)
        if (tokenData.used) {
            // TOKEN REUSE DETECTED - Security incident!
            await this.handleTokenTheft(tokenData.userId, refreshToken);
            throw new Error('Token reuse detected - all tokens revoked');
        }

        // 3. Mark current token as used (but don't delete yet)
        tokenData.used = true;
        await redis.setex(tokenKey, 7 * 24 * 60 * 60, JSON.stringify(tokenData));

        // 4. Generate new token pair (rotation)
        const userRoles = await this.getUserRoles(tokenData.userId);
        const newTokenPair = await this.generateTokenPair(
            tokenData.userId,
            userRoles,
            tokenData.clientId
        );

        // 5. Invalidate old refresh token after successful rotation
        await redis.del(tokenKey);

        return newTokenPair;
    }

    /**
     * Handle token theft scenario
     */
    async handleTokenTheft(userId, compromisedToken) {
        console.error(`[SECURITY] Token theft detected for user: ${userId}`);

        // 1. Revoke ALL refresh tokens for this user
        const userTokensPattern = `refresh_token:*`;
        const keys = await redis.keys(userTokensPattern);

        for (const key of keys) {
            const tokenDataStr = await redis.get(key);
            if (tokenDataStr) {
                const tokenData = JSON.parse(tokenDataStr);
                if (tokenData.userId === userId) {
                    await redis.del(key);
                }
