        }

        // 2. Log security incident
        await this.logSecurityIncident(userId, 'refresh_token_reuse', {
            compromisedToken: compromisedToken.substring(0, 10) + '...',
            timestamp: new Date().toISOString()
        });

        // 3. Trigger security alert
        await this.triggerSecurityAlert(userId, 'Token reuse detected');

        // 4. Force user session termination
        await this.invalidateUserSessions(userId);
    }

