import com.azure.security.keyvault.keys.KeyClient;
import com.azure.security.keyvault.keys.KeyClientBuilder;
import com.azure.security.keyvault.keys.cryptography.CryptographyClient;
import com.azure.security.keyvault.keys.cryptography.CryptographyClientBuilder;
import com.azure.security.keyvault.keys.cryptography.models.EncryptionAlgorithm;
import com.azure.security.keyvault.keys.cryptography.models.EncryptResult;
import com.azure.security.keyvault.keys.cryptography.models.DecryptResult;
import com.azure.identity.DefaultAzureCredential;
import org.springframework.stereotype.Service;
import org.springframework.beans.factory.annotation.Value;

import java.nio.charset.StandardCharsets;
import java.util.Base64;

@Service
public class TokenEncryptionService {

    private final CryptographyClient cryptoClient;
    private static final EncryptionAlgorithm ALGORITHM = EncryptionAlgorithm.RSA_OAEP_256;

    public TokenEncryptionService(
        @Value("${azure.keyvault.url}") String keyVaultUrl,
        @Value("${azure.keyvault.key-name}") String keyName
    ) {
        DefaultAzureCredential credential = new DefaultAzureCredential();

        KeyClient keyClient = new KeyClientBuilder()
            .vaultUrl(keyVaultUrl)
            .credential(credential)
            .buildClient();

        String keyId = keyClient.getKey(keyName).getId();

        this.cryptoClient = new CryptographyClientBuilder()
            .credential(credential)
            .keyIdentifier(keyId)
            .buildClient();
    }

    /**
     * Encrypt OAuth token before storing
     */
    public String encryptToken(String plainToken) {
        try {
            byte[] tokenBytes = plainToken.getBytes(StandardCharsets.UTF_8);
            EncryptResult encryptResult = cryptoClient.encrypt(ALGORITHM, tokenBytes);
            return Base64.getEncoder().encodeToString(encryptResult.getCipherText());
        } catch (Exception e) {
            throw new RuntimeException("Token encryption failed", e);
        }
    }

    /**
     * Decrypt OAuth token when retrieving
     */
    public String decryptToken(String encryptedToken) {
        try {
            byte[] cipherText = Base64.getDecoder().decode(encryptedToken);
            DecryptResult decryptResult = cryptoClient.decrypt(ALGORITHM, cipherText);
            return new String(decryptResult.getPlainText(), StandardCharsets.UTF_8);
        } catch (Exception e) {
            throw new RuntimeException("Token decryption failed", e);
        }
    }
}

