// Express.js 4.x - Token Encryption with AWS KMS
// File: services/tokenEncryption.js
const { KMSClient, EncryptCommand, DecryptCommand } = require('@aws-sdk/client-kms');
const crypto = require('crypto');

class TokenEncryptionService {
    constructor() {
        this.kmsClient = new KMSClient({ region: process.env.AWS_REGION });
        this.keyId = process.env.AWS_KMS_KEY_ID;
    }

    /**
     * Encrypt OAuth token using AWS KMS
     */
    async encryptToken(plainToken) {
        try {
            const command = new EncryptCommand({
                KeyId: this.keyId,
                Plaintext: Buffer.from(plainToken, 'utf-8'),
                EncryptionAlgorithm: 'RSAES_OAEP_SHA_256'
            });

            const response = await this.kmsClient.send(command);
            return Buffer.from(response.CiphertextBlob).toString('base64');
        } catch (error) {
            console.error('Token encryption failed:', error);
            throw new Error('Failed to encrypt token');
        }
    }

    /**
     * Decrypt OAuth token using AWS KMS
     */
    async decryptToken(encryptedToken) {
        try {
            const command = new DecryptCommand({
                CiphertextBlob: Buffer.from(encryptedToken, 'base64'),
                KeyId: this.keyId,
                EncryptionAlgorithm: 'RSAES_OAEP_SHA_256'
            });

            const response = await this.kmsClient.send(command);
            return Buffer.from(response.Plaintext).toString('utf-8');
        } catch (error) {
            console.error('Token decryption failed:', error);
            throw new Error('Failed to decrypt token');
        }
    }

    /**
     * Alternative: Encrypt with AES-256-GCM using data key from KMS
     * More efficient for large volumes
     */
    async encryptTokenWithDataKey(plainToken) {
        // Generate data encryption key from KMS
        const { GenerateDataKeyCommand } = require('@aws-sdk/client-kms');
        const dataKeyCommand = new GenerateDataKeyCommand({
            KeyId: this.keyId,
            KeySpec: 'AES_256'
        });

        const dataKeyResponse = await this.kmsClient.send(dataKeyCommand);
        const plaintextKey = dataKeyResponse.Plaintext;
        const encryptedDataKey = Buffer.from(dataKeyResponse.CiphertextBlob).toString('base64');

        // Encrypt token with data key using AES-256-GCM
        const iv = crypto.randomBytes(12);
        const cipher = crypto.createCipheriv('aes-256-gcm', plaintextKey, iv);

        let encrypted = cipher.update(plainToken, 'utf8', 'base64');
        encrypted += cipher.final('base64');
        const authTag = cipher.getAuthTag().toString('base64');

        // Return encrypted token bundle
        return JSON.stringify({
            encryptedToken: encrypted,
            encryptedDataKey: encryptedDataKey,
            iv: iv.toString('base64'),
            authTag: authTag
        });
    }

    async decryptTokenWithDataKey(encryptedBundle) {
        const bundle = JSON.parse(encryptedBundle);

        // Decrypt data key using KMS
        const command = new DecryptCommand({
            CiphertextBlob: Buffer.from(bundle.encryptedDataKey, 'base64'),
            KeyId: this.keyId
        });

        const response = await this.kmsClient.send(command);
        const plaintextKey = response.Plaintext;

        // Decrypt token with data key
        const decipher = crypto.createDecipheriv(
            'aes-256-gcm',
            plaintextKey,
            Buffer.from(bundle.iv, 'base64')
        );
        decipher.setAuthTag(Buffer.from(bundle.authTag, 'base64'));

        let decrypted = decipher.update(bundle.encryptedToken, 'base64', 'utf8');
        decrypted += decipher.final('utf8');

        return decrypted;
    }
