// Express.js - Secure Token Storage in Database
// File: models/OAuthToken.js
const mongoose = require('mongoose');
const tokenEncryption = require('../services/tokenEncryption');

const oauthTokenSchema = new mongoose.Schema({
    userId: { type: String, required: true, index: true },
    clientId: { type: String, required: true },
    encryptedAccessToken: { type: String, required: true },
    encryptedRefreshToken: { type: String },
    scope: [String],
    expiresAt: { type: Date, required: true },
    createdAt: { type: Date, default: Date.now }
});

// Encrypt tokens before saving
oauthTokenSchema.pre('save', async function(next) {
    if (this.isModified('accessToken')) {
        this.encryptedAccessToken = await tokenEncryption.encryptToken(this.accessToken);
        delete this.accessToken; // Remove plaintext
    }
    if (this.isModified('refreshToken')) {
        this.encryptedRefreshToken = await tokenEncryption.encryptToken(this.refreshToken);
        delete this.refreshToken; // Remove plaintext
    }
    next();
});

// Decrypt tokens when retrieving
oauthTokenSchema.methods.getDecryptedTokens = async function() {
    return {
        accessToken: await tokenEncryption.decryptToken(this.encryptedAccessToken),
        refreshToken: this.encryptedRefreshToken 
            ? await tokenEncryption.decryptToken(this.encryptedRefreshToken)
            : null
    };
};

module.exports = mongoose.model('OAuthToken', oauthTokenSchema);

// Client-side: NEVER store tokens in localStorage - use httpOnly cookies
// File: middleware/secureCookies.js
const secureCookieOptions = {
    httpOnly: true,      // Prevent XSS access
    secure: true,        // HTTPS only
    sameSite: 'strict',  // CSRF protection
    maxAge: 10 * 60 * 1000, // 10 minutes
    path: '/'
};

// Set encrypted token in httpOnly cookie
function setAuthCookie(res, accessToken) {
    res.cookie('access_token', accessToken, secureCookieOptions);
}

module.exports = { setAuthCookie, secureCookieOptions };
